import java.util.ArrayList;
import java.util.Arrays;
import java.util.Comparator;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.regex.Pattern;

public class Solution {
    public static String[] solve(String[] code, String[] businessLine, boolean[] isActive) {
        List<String[]> validCoupons = new ArrayList<>();
        Map<String, Integer> businessOrder = new HashMap<>();
        businessOrder.put("electronics", 0);
        businessOrder.put("grocery", 1);
        businessOrder.put("pharmacy", 2);
        businessOrder.put("restaurant", 3);

        for (int i = 0; i < code.length; i++) {
            // Check code is not empty and matches regex
            if (code[i].isEmpty()) {
                continue;
            }
            if (!Pattern.matches("^[a-zA-Z0-9_]+$", code[i])) {
                continue;
            }
            // Check businessLine is valid
            String bl = businessLine[i];
            if (!bl.equals("electronics") && 
                !bl.equals("grocery") && 
                !bl.equals("pharmacy") && 
                !bl.equals("restaurant")) {
                continue;
            }
            // Check isActive is true
            if (!isActive[i]) {
                continue;
            }
            // All conditions met
            validCoupons.add(new String[]{code[i], bl});
        }

        // Sort the valid coupons
        validCoupons.sort((a, b) -> {
            int orderA = businessOrder.get(a[1]);
            int orderB = businessOrder.get(b[1]);
            if (orderA != orderB) {
                return Integer.compare(orderA, orderB);
            }
            return a[0].compareTo(b[0]);
        });

        // Collect the codes into the result array
        String[] result = new String[validCoupons.size()];
        for (int i = 0; i < result.length; i++) {
            result[i] = validCoupons.get(i)[0];
        }
        return result;
    }
}

