public static String[] solve(String[] code, String[] businessLine, boolean[] isActive) {
    // Step 1: Filter valid coupons
    ArrayList<String[]> validCoupons = new ArrayList<>();
    for (int i = 0; i < code.length; i++) {
        String c = code[i];
        String bl = businessLine[i];
        boolean active = isActive[i];

        // Check code is not empty and valid
        if (c.isEmpty()) continue;
        if (!c.matches("^[a-zA-Z0-9_]+$")) continue;

        // Check business line
        if (!bl.equals("electronics") && !bl.equals("grocery") && 
            !bl.equals("pharmacy") && !bl.equals("restaurant")) {
            continue;
        }

        // Check active
        if (!active) continue;

        // Add to valid coupons
        validCoupons.add(new String[]{bl, c});
    }

    // Step 2: Sort the valid coupons
    // Sort by businessLine order, then code
    validCoupons.sort((a, b) -> {
        int orderA = getBusinessOrder(a[0]);
        int orderB = getBusinessOrder(b[0]);
        if (orderA != orderB) return orderA - orderB;
        return a[1].compareTo(b[1]);
    });

    // Step 3: Extract the codes into the result array
    String[] result = new String[validCoupons.size()];
    for (int i = 0; i < result.length; i++) {
        result[i] = validCoupons.get(i)[1];
    }
    return result;
}

// Helper method to get business order
private static int getBusinessOrder(String businessLine) {
    if (businessLine.equals("electronics")) return 0;
    if (businessLine.equals("grocery")) return 1;
    if (businessLine.equals("pharmacy")) return 2;
    if (businessLine.equals("restaurant")) return 3;
    throw new IllegalArgumentException("Invalid business line");
}

