import java.util.ArrayList;
import java.util.Arrays;
import java.util.Comparator;

public class Solution {
    public static String[] solve(String[] code, String[] businessLine, boolean[] isActive) {
        ArrayList<String[]> validCoupons = new ArrayList<>();
        for (int i = 0; i < code.length; i++) {
            String c = code[i];
            String bl = businessLine[i];
            boolean active = isActive[i];

            if (c.isEmpty()) continue;
            if (!c.matches("^[a-zA-Z0-9_]+$")) continue;

            if (!bl.equals("electronics") && !bl.equals("grocery") && 
                !bl.equals("pharmacy") && !bl.equals("restaurant")) {
                continue;
            }

            if (!active) continue;

            validCoupons.add(new String[]{bl, c});
        }

        validCoupons.sort((a, b) -> {
            int orderA = 0;
            if (a[0].equals("electronics")) orderA = 0;
            else if (a[0].equals("grocery")) orderA = 1;
            else if (a[0].equals("pharmacy")) orderA = 2;
            else if (a[0].equals("restaurant")) orderA = 3;

            int orderB = 0;
            if (b[0].equals("electronics")) orderB = 0;
            else if (b[0].equals("grocery")) orderB = 1;
            else if (b[0].equals("pharmacy")) orderB = 2;
            else if (b[0].equals("restaurant")) orderB = 3;

            if (orderA != orderB) return orderA - orderB;
            return a[1].compareTo(b[1]);
        });

        String[] result = new String[validCoupons.size()];
        for (int i = 0; i < result.length; i++) {
            result[i] = validCoupons.get(i)[1];
        }
        return result;
    }
}

